contracts/SimpleAgricultureToken.sol.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title SimpleAgricultureToken
 * @dev Simplified agricultural asset token for the demo
 */
contract SimpleAgricultureToken is ERC20, AccessControl, Pausable {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");

    string public assetType;
    address public centralAuthority;

    // Asset verification and expiry tracking
    mapping(address => bool) public assetVerificationStatus;
    mapping(address => uint256) public assetExpiry;
    mapping(address => uint256) public mintTimestamp;

    // Default expiry periods (in seconds)
    uint256 public defaultExpiryPeriod;

    // Events
    event AssetVerified(address indexed holder, uint256 amount, string location, uint256 expiryDate);
    event AssetExpired(address indexed holder, uint256 amount);
    event ExpiryPeriodUpdated(uint256 oldPeriod, uint256 newPeriod);

    constructor(
        string memory name,
        string memory symbol,
        string memory _assetType,
        address _centralAuthority,
        address defaultAdmin,
        uint256 _defaultExpiryPeriod
    ) ERC20(name, symbol) {
        assetType = _assetType;
        centralAuthority = _centralAuthority;
        defaultExpiryPeriod = _defaultExpiryPeriod;

        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
        _grantRole(MINTER_ROLE, _centralAuthority);
        _grantRole(PAUSER_ROLE, defaultAdmin);
    }

    /**
     * @dev Mint tokens representing verified assets
     */
    function mint(
        address to, 
        uint256 amount, 
        uint256 expiryTimestamp,
        string memory location
    ) external onlyRole(MINTER_ROLE) {
        require(to != address(0), "Invalid recipient");
        require(expiryTimestamp > block.timestamp, "Expiry must be in future");

        _mint(to, amount);
        assetVerificationStatus[to] = true;
        assetExpiry[to] = expiryTimestamp;
        mintTimestamp[to] = block.timestamp;

        emit AssetVerified(to, amount, location, expiryTimestamp);
    }

    /**
     * @dev Mint tokens with default expiry period
     */
    function mintWithDefaultExpiry(
        address to, 
        uint256 amount, 
        string memory location
    ) external onlyRole(MINTER_ROLE) {
        require(to != address(0), "Invalid recipient");
        require(defaultExpiryPeriod > 0, "Default expiry period not set");

        uint256 expiryTimestamp = block.timestamp + defaultExpiryPeriod;

        _mint(to, amount);
        assetVerificationStatus[to] = true;
        assetExpiry[to] = expiryTimestamp;
        mintTimestamp[to] = block.timestamp;

        emit AssetVerified(to, amount, location, expiryTimestamp);
    }

    /**
     * @dev Burn expired tokens
     */
    function burnExpiredTokens(address holder) external onlyRole(MINTER_ROLE) {
        require(
            assetExpiry[holder] > 0 && block.timestamp >= assetExpiry[holder],
            "Assets not expired"
        );

        uint256 balance = balanceOf(holder);
        if (balance > 0) {
            _burn(holder, balance);
            assetVerificationStatus[holder] = false;
            emit AssetExpired(holder, balance);
        }
    }

    /**
     * @dev Allow farmers to burn their own assets early (for spoilage, disposal, etc.)
     */
    function burnOwnAssets(uint256 amount, string memory reason) external {
        require(amount > 0, "Amount must be greater than 0");
        require(balanceOf(msg.sender) >= amount, "Insufficient balance");

        _burn(msg.sender, amount);

        // If burning all tokens, reset verification status
        if (balanceOf(msg.sender) == 0) {
            assetVerificationStatus[msg.sender] = false;
        }

        emit AssetExpired(msg.sender, amount);
    }

    /**
     * @dev Check if assets are valid (verified and not expired)
     */
    function areAssetsValid(address holder) external view returns (bool) {
        return assetVerificationStatus[holder] && 
               (assetExpiry[holder] == 0 || block.timestamp < assetExpiry[holder]);
    }

    /**
     * @dev Override transfer to check asset validity (only for non-zero holders)
     */
    function transfer(address to, uint256 amount) public override returns (bool) {
        require(!paused(), "Token transfers are paused");
        // Only check validity if sender has tokens and verification status
        if (balanceOf(msg.sender) > 0 && assetVerificationStatus[msg.sender]) {
            require(this.areAssetsValid(msg.sender), "Assets not valid for transfer");
        }
        return super.transfer(to, amount);
    }

    /**
     * @dev Override transferFrom to check asset validity (only for non-zero holders)
     */
    function transferFrom(address from, address to, uint256 amount) public override returns (bool) {
        require(!paused(), "Token transfers are paused");
        // Only check validity if sender has tokens and verification status
        if (balanceOf(from) > 0 && assetVerificationStatus[from]) {
            require(this.areAssetsValid(from), "Assets not valid for transfer");
        }
        return super.transferFrom(from, to, amount);
    }

    /**
     * @dev Pause token transfers
     */
    function pause() external onlyRole(PAUSER_ROLE) {
        _pause();
    }

    /**
     * @dev Unpause token transfers
     */
    function unpause() external onlyRole(PAUSER_ROLE) {
        _unpause();
    }

    /**
     * @dev Update default expiry period (admin only)
     */
    function updateDefaultExpiryPeriod(uint256 newExpiryPeriod) external onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256 oldPeriod = defaultExpiryPeriod;
        defaultExpiryPeriod = newExpiryPeriod;
        emit ExpiryPeriodUpdated(oldPeriod, newExpiryPeriod);
    }

    /**
     * @dev Check time remaining until expiry
     */
    function getTimeUntilExpiry(address holder) external view returns (uint256) {
        if (assetExpiry[holder] == 0) return type(uint256).max; // No expiry set
        if (block.timestamp >= assetExpiry[holder]) return 0; // Already expired
        return assetExpiry[holder] - block.timestamp;
    }

    /**
     * @dev Check if tokens are expired
     */
    function isExpired(address holder) external view returns (bool) {
        return assetExpiry[holder] > 0 && block.timestamp >= assetExpiry[holder];
    }

    /**
     * @dev Returns detailed token information including expiry
     */
    function getTokenInfo() external view returns (
        string memory tokenName,
        string memory tokenSymbol,
        string memory asset,
        uint256 totalSupply,
        address authority,
        uint256 defaultExpiry
    ) {
        return (
            name(),
            symbol(),
            assetType,
            super.totalSupply(),
            centralAuthority,
            defaultExpiryPeriod
        );
    }

    /**
     * @dev Get detailed holder information
     */
    function getHolderInfo(address holder) external view returns (
        uint256 balance,
        bool verified,
        uint256 expiryDate,
        uint256 mintDate,
        bool expired
    ) {
        return (
            balanceOf(holder),
            assetVerificationStatus[holder],
            assetExpiry[holder],
            mintTimestamp[holder],
            this.isExpired(holder)
        );
    }
}

contracts/SimpleAssetEscrow.sol.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./SimpleAgricultureToken.sol";
import "./SimpleCentralAuthority.sol";

/**
 * @title SimpleAssetEscrow
 * @dev Simplified escrow contract for agricultural asset trading
 */
contract SimpleAssetEscrow is ReentrancyGuard, Ownable {
    struct Order {
        address buyer;
        address seller;
        address paymentToken;
        address[] assetTokens;
        uint256[] assetAmounts;
        uint256 paymentAmount;
        uint256 expirationTime;
        bool paymentDeposited;
        bool assetsDelivered;
        bool buyerVerified;
        bool sellerVerified;
        bool authorityVerified;
        bool completed;
        bool cancelled;
    }

    mapping(uint256 => Order) public orders;
    uint256 public orderCounter;

    SimpleCentralAuthority public centralAuthority;
    address public feeCollector;
    uint256 public feePercentage = 100; // 1% = 100 basis points

    // Events
    event OrderCreated(uint256 indexed orderId, address indexed buyer, address indexed seller);
    event PaymentDeposited(uint256 indexed orderId, uint256 amount);
    event AssetsDelivered(uint256 indexed orderId);
    event OrderVerified(uint256 indexed orderId, address indexed verifier);
    event OrderCompleted(uint256 indexed orderId);
    event OrderCancelled(uint256 indexed orderId);

    constructor(address _centralAuthority, address _feeCollector, address _owner) Ownable(_owner) {
        centralAuthority = SimpleCentralAuthority(_centralAuthority);
        feeCollector = _feeCollector;
    }

    /**
     * @dev Create a new purchase order
     */
    function createOrder(
        address seller,
        address paymentToken,
        address[] memory assetTokens,
        uint256[] memory assetAmounts,
        uint256 paymentAmount,
        uint256 expirationTime
    ) external returns (uint256) {
        require(seller != address(0), "Invalid seller");
        require(paymentToken != address(0), "Invalid payment token");
        require(assetTokens.length == assetAmounts.length, "Array length mismatch");
        require(assetTokens.length > 0, "No assets specified");
        require(paymentAmount > 0, "Invalid payment amount");
        require(expirationTime > block.timestamp, "Invalid expiration time");
        require(centralAuthority.isSupplierApproved(seller), "Seller not approved");

        uint256 orderId = orderCounter++;

        orders[orderId] = Order({
            buyer: msg.sender,
            seller: seller,
            paymentToken: paymentToken,
            assetTokens: assetTokens,
            assetAmounts: assetAmounts,
            paymentAmount: paymentAmount,
            expirationTime: expirationTime,
            paymentDeposited: false,
            assetsDelivered: false,
            buyerVerified: false,
            sellerVerified: false,
            authorityVerified: false,
            completed: false,
            cancelled: false
        });

        emit OrderCreated(orderId, msg.sender, seller);
        return orderId;
    }

    /**
     * @dev Buyer deposits payment to escrow
     */
    function depositPayment(uint256 orderId) external nonReentrant {
        Order storage order = orders[orderId];
        require(msg.sender == order.buyer, "Only buyer can deposit payment");
        require(!order.paymentDeposited, "Payment already deposited");
        require(!order.cancelled, "Order cancelled");
        require(block.timestamp < order.expirationTime, "Order expired");

        IERC20(order.paymentToken).transferFrom(msg.sender, address(this), order.paymentAmount);
        order.paymentDeposited = true;

        emit PaymentDeposited(orderId, order.paymentAmount);
    }

    /**
     * @dev Seller delivers assets to escrow
     */
    function deliverAssets(uint256 orderId) external nonReentrant {
        Order storage order = orders[orderId];
        require(msg.sender == order.seller, "Only seller can deliver assets");
        require(order.paymentDeposited, "Payment not deposited");
        require(!order.assetsDelivered, "Assets already delivered");
        require(!order.cancelled, "Order cancelled");
        require(block.timestamp < order.expirationTime, "Order expired");

        // Transfer all asset tokens to escrow
        for (uint256 i = 0; i < order.assetTokens.length; i++) {
            IERC20(order.assetTokens[i]).transferFrom(
                msg.sender, 
                address(this), 
                order.assetAmounts[i]
            );
        }

        order.assetsDelivered = true;
        emit AssetsDelivered(orderId);
    }

    /**
     * @dev Verify order completion (buyer, seller, or authority)
     */
    function verifyOrder(uint256 orderId) external {
        Order storage order = orders[orderId];
        require(order.paymentDeposited && order.assetsDelivered, "Order not ready for verification");
        require(!order.completed && !order.cancelled, "Order already finalized");
        require(block.timestamp < order.expirationTime, "Order expired");

        if (msg.sender == order.buyer) {
            order.buyerVerified = true;
        } else if (msg.sender == order.seller) {
            order.sellerVerified = true;
        } else if (msg.sender == address(centralAuthority)) {
            order.authorityVerified = true;
        } else {
            revert("Unauthorized verifier");
        }

        emit OrderVerified(orderId, msg.sender);

        // Check if order can be completed (need at least 2 verifications)
        uint256 verificationCount = 0;
        if (order.buyerVerified) verificationCount++;
        if (order.sellerVerified) verificationCount++;
        if (order.authorityVerified) verificationCount++;

        if (verificationCount >= 2) {
            _completeOrder(orderId);
        }
    }

    /**
     * @dev Cancel order (before completion)
     */
    function cancelOrder(uint256 orderId) external {
        Order storage order = orders[orderId];
        require(
            msg.sender == order.buyer || 
            msg.sender == order.seller || 
            msg.sender == owner(),
            "Unauthorized"
        );
        require(!order.completed, "Order already completed");
        require(!order.cancelled, "Order already cancelled");

        order.cancelled = true;

        // Return payment to buyer if deposited
        if (order.paymentDeposited) {
            IERC20(order.paymentToken).transfer(order.buyer, order.paymentAmount);
        }

        // Return assets to seller if delivered
        if (order.assetsDelivered) {
            for (uint256 i = 0; i < order.assetTokens.length; i++) {
                IERC20(order.assetTokens[i]).transfer(order.seller, order.assetAmounts[i]);
            }
        }

        emit OrderCancelled(orderId);
    }

    /**
     * @dev Complete order and release funds/assets
     */
    function _completeOrder(uint256 orderId) internal {
        Order storage order = orders[orderId];
        order.completed = true;

        // Calculate fee
        uint256 fee = (order.paymentAmount * feePercentage) / 10000;
        uint256 sellerPayment = order.paymentAmount - fee;

        // Transfer payment to seller (minus fee)
        IERC20(order.paymentToken).transfer(order.seller, sellerPayment);

        // Transfer fee to fee collector
        if (fee > 0) {
            IERC20(order.paymentToken).transfer(feeCollector, fee);
        }

        // Transfer assets to buyer
        for (uint256 i = 0; i < order.assetTokens.length; i++) {
            IERC20(order.assetTokens[i]).transfer(order.buyer, order.assetAmounts[i]);
        }

        emit OrderCompleted(orderId);
    }

    /**
     * @dev Get order details
     */
    function getOrder(uint256 orderId) external view returns (Order memory) {
        return orders[orderId];
    }

    /**
     * @dev Update fee percentage (only owner)
     */
    function setFeePercentage(uint256 newFeePercentage) external onlyOwner {
        require(newFeePercentage <= 1000, "Fee too high"); // Max 10%
        feePercentage = newFeePercentage;
    }

    /**
     * @dev Update fee collector (only owner)
     */
    function setFeeCollector(address newFeeCollector) external onlyOwner {
        require(newFeeCollector != address(0), "Invalid fee collector");
        feeCollector = newFeeCollector;
    }
}

contracts/SimpleCentralAuthority.sol.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "./SimpleAgricultureToken.sol";

/**
 * @title SimpleCentralAuthority
 * @dev Simplified central authority for agricultural asset verification
 */
contract SimpleCentralAuthority is AccessControl, Pausable {
    bytes32 public constant VERIFIER_ROLE = keccak256("VERIFIER_ROLE");
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    struct Supplier {
        string name;
        string location;
        string[] assetTypes;
        bool isApproved;
        uint256 registrationTime;
    }

    struct AssetVerification {
        address supplier;
        string assetType;
        uint256 quantity;
        string location;
        string verificationNotes;
        uint256 timestamp;
        address verifier;
    }

    mapping(address => Supplier) public suppliers;
    mapping(address => mapping(string => address)) public registeredTokens; // supplier => assetType => token
    mapping(uint256 => AssetVerification) public assetVerifications;
    uint256 public verificationCounter;

    // Events
    event SupplierRegistered(address indexed supplier, string name);
    event SupplierApproved(address indexed supplier);
    event TokenRegistered(address indexed tokenAddress, string assetType);
    event AssetVerified(uint256 indexed verificationId, address indexed supplier, string assetType, uint256 quantity);
    event TokenMinted(address indexed token, address indexed recipient, uint256 amount);

    constructor(address defaultAdmin) {
        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
        _grantRole(VERIFIER_ROLE, defaultAdmin);
        _grantRole(OPERATOR_ROLE, defaultAdmin);
    }

    /**
     * @dev Register a new supplier
     */
    function registerSupplier(
        address supplierAddress,
        string memory name,
        string memory location,
        string[] memory assetTypes
    ) external onlyRole(OPERATOR_ROLE) {
        require(supplierAddress != address(0), "Invalid supplier address");
        require(suppliers[supplierAddress].registrationTime == 0, "Supplier already registered");

        suppliers[supplierAddress] = Supplier({
            name: name,
            location: location,
            assetTypes: assetTypes,
            isApproved: false,
            registrationTime: block.timestamp
        });

        emit SupplierRegistered(supplierAddress, name);
    }

    /**
     * @dev Approve a registered supplier
     */
    function approveSupplier(address supplierAddress) external onlyRole(VERIFIER_ROLE) {
        require(suppliers[supplierAddress].registrationTime > 0, "Supplier not registered");
        suppliers[supplierAddress].isApproved = true;
        emit SupplierApproved(supplierAddress);
    }

    /**
     * @dev Register a token for an asset type
     */
    function registerToken(address tokenAddress, string memory assetType) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(tokenAddress != address(0), "Invalid token address");
        registeredTokens[msg.sender][assetType] = tokenAddress;
        emit TokenRegistered(tokenAddress, assetType);
    }

    /**
     * @dev Verify asset backing for a supplier
     */
    function verifyAssetBacking(
        address supplier,
        string memory assetType,
        uint256 quantity,
        string memory location,
        string memory verificationNotes
    ) external onlyRole(VERIFIER_ROLE) returns (uint256) {
        require(suppliers[supplier].isApproved, "Supplier not approved");

        uint256 verificationId = verificationCounter++;

        assetVerifications[verificationId] = AssetVerification({
            supplier: supplier,
            assetType: assetType,
            quantity: quantity,
            location: location,
            verificationNotes: verificationNotes,
            timestamp: block.timestamp,
            verifier: msg.sender
        });

        emit AssetVerified(verificationId, supplier, assetType, quantity);
        return verificationId;
    }

    /**
     * @dev Authorize token minting after asset verification
     */
    function authorizeTokenMinting(
        address tokenAddress,
        address recipient,
        uint256 amount,
        uint256 createdAt,
        uint256 expiryTimestamp,
        string memory location
    ) external onlyRole(VERIFIER_ROLE) {
        require(tokenAddress != address(0), "Invalid token address");
        require(suppliers[recipient].isApproved, "Recipient not approved supplier");

        SimpleAgricultureToken token = SimpleAgricultureToken(tokenAddress);
        token.mint(recipient, amount, expiryTimestamp, location);

        emit TokenMinted(tokenAddress, recipient, amount);
    }

    /**
     * @dev Emergency burn expired tokens
     */
    function emergencyBurnExpiredTokens(address tokenAddress, address holder) 
        external 
        onlyRole(DEFAULT_ADMIN_ROLE) 
    {
        SimpleAgricultureToken(tokenAddress).burnExpiredTokens(holder);
    }

    /**
     * @dev Check if supplier is approved
     */
    function isSupplierApproved(address supplier) external view returns (bool) {
        return suppliers[supplier].isApproved;
    }

    /**
     * @dev Get supplier information
     */
    function getSupplierInfo(address supplier) external view returns (
        string memory name,
        string memory location,
        string[] memory assetTypes,
        bool isApproved,
        uint256 registrationTime
    ) {
        Supplier memory sup = suppliers[supplier];
        return (sup.name, sup.location, sup.assetTypes, sup.isApproved, sup.registrationTime);
    }

    /**
     * @dev Get asset verification details
     */
    function getAssetVerification(uint256 verificationId) external view returns (AssetVerification memory) {
        return assetVerifications[verificationId];
    }

    /**
     * @dev Pause the contract
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @dev Unpause the contract
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

